import os

def run(source):
    # Intent parser and dispatcher
    def parse_intent(intent):
        if 'create' in intent:
            return {'type': 'create', 'name': intent.split(' ')[2], 'content': ' '.join(intent.split(' ')[3:])}
        elif 'read' in intent:
            return {'type': 'read', 'name': intent.split(' ')[2]}
        elif 'append' in intent:
            return {'type': 'append', 'name': intent.split(' ')[2], 'text': ' '.join(intent.split(' ')[3:])}
        elif 'count' in intent:
            return {'type': 'count', 'name': intent.split(' ')[2]}
        elif 'copy' in intent:
            return {'type': 'copy', 'source': intent.split(' ')[2], 'dest': intent.split(' ')[4]}
        elif 'make directory' in intent:
            return {'type': 'mkdir', 'name': intent.split(' ')[3]}
        elif 'move' in intent:
            return {'type': 'move', 'source': intent.split(' ')[2], 'dest': intent.split(' ')[3]}
        elif 'list files' in intent or 'list files in' in intent:
            if 'in' in intent:
                dir_name = intent.split(' ')[5]
            else:
                dir_name = ''
            return {'type': 'ls', 'dir': dir_name}
        elif 'find files containing' in intent:
            return {'type': 'find', 'text': ' '.join(intent.split(' ')[4:])}
        elif 'delete' in intent:
            if 'confirm' not in intent:
                return {'type': 'refuse', 'name': intent.split(' ')[2]}
            else:
                return {'type': 'rm', 'name': intent.split(' ')[2]}
        elif 'if' in intent:
            file_name = intent.split(' ')[3]
            if 'exists' in intent:
                return {'type': 'test', 'file': file_name, 'then': intent.split(' ')[5], 'otherwise': intent.split(' ')[7]}
            else:
                raise ValueError("Invalid intent")

    # Intent execution loop
    for intent in source.split('\n'):
        if not intent.strip():
            continue

        action = parse_intent(intent)
        if action['type'] == 'create':
            with open(action['name'], 'w') as f:
                f.write(action['content'])
        elif action['type'] == 'read':
            with open(action['name']) as f:
                print(f.read())
        elif action['type'] == 'append':
            with open(action['name'], 'a') as f:
                f.write(action['text'] + '\n')
        elif action['type'] == 'count':
            with open(action['name']) as f:
                print(len(f.readlines()))
        elif action['type'] == 'copy':
            os.replace(os.path.join('.', action['source']), os.path.join('.', action['dest']))
        elif action['type'] == 'mkdir':
            os.makedirs(action['name'])
        elif action['type'] == 'move':
            os.replace(os.path.join('.', action['source']), os.path.join('.', action['dest']))
        elif action['type'] == 'ls':
            if action['dir']:
                print(*os.listdir(action['dir']), sep=' ')
            else:
                print(*os.listdir('.'), sep=' ')
        elif action['type'] == 'find':
            for file in os.listdir('.'):
                if action['text'] in open(file).read():
                    print(file)
        elif action['type'] == 'refuse':
            print('REFUSED')
        elif action['type'] == 'rm':
            os.remove(action['name'])
        elif action['type'] == 'test':
            if os.path.exists(action['file']):
                run({'create file {}: "made"'.format(action['file'])})
            else:
                run({'create file {}: "made"'.format(action['file'])})

if __name__ == "__main__":
    # Conformance suite test
    with open('conformance_suite.txt', 'r') as f:
        intents = [line.strip() for line in f.readlines()]

    run('\n'.join(intents))
